### ChunkingStrategy
### TokenEstimator

## Core Types

```rust
/// Metadata about the source file being chunked
pub struct SourceMetadata {
    pub file_path: String,
    pub extension: String,
    pub language: Option<String>,
    pub scope_id: String,
    pub source_version: String,
}

/// Raw chunk produced by a ChunkingStrategy (pre-budget, pre-merge)
pub struct RawChunk {
    pub content: String,
    pub chunk_type: String,             // "function_item", "heading_section", "key_value", "file"
    pub start_line: u32,
    pub end_line: u32,
    pub metadata: ChunkMetadata,
}

/// Additional chunk metadata for provenance and graph linking
pub struct ChunkMetadata {
    pub source_file: String,
    pub language: Option<String>,
    pub parent_chunk_id: Option<Uuid>,  // for split chunks — links back to original
    pub merge_group: Option<String>,    // hint for which chunks can merge
}

/// Final chunk after pipeline processing — ready for embedding
pub struct ProcessedChunk {
    pub content: String,                // may include overlap prefix
    pub original_content: String,       // without overlap (for display/citation)
    pub chunk_type: String,
    pub start_line: u32,
    pub end_line: u32,
    pub metadata: ChunkMetadata,
    pub token_estimate: usize,
    pub processing: ProcessingInfo,
}

/// How this chunk was processed by the pipeline
pub struct ProcessingInfo {
    pub strategy_name: String,
    pub was_split: bool,
    pub was_merged: bool,
    pub overlap_tokens: usize,
}

/// Raw source file returned by IngestionAdapter
pub struct SourceFile {
    pub content: String,
    pub metadata: SourceMetadata,
}
```
